var QUESTIONS_THEORY_11 = [
{type:"mcq",diff:"easy",en:{q:"What does WWW stand for in the context of the Internet?",opts:["World Wide Web","World Web Wide","Web Wide World","Wide World Web"],ans:0,exp:"WWW stands for World Wide Web. It was created by Tim Berners-Lee in 1990 at CERN. It is a vast network of interlinked hypertext documents and multimedia resources accessed via the Internet using HTTP."},hi:{q:"इंटरनेट के संदर्भ में WWW का क्या अर्थ है?",opts:["वर्ल्ड वाइड वेब","वर्ल्ड वेब वाइड","वेब वाइड वर्ल्ड","वाइड वर्ल्ड वेब"],ans:0,exp:"WWW का अर्थ वर्ल्ड वाइड वेब है। इसे 1990 में सर्न (CERN) में टिम बर्नर्स-ली द्वारा बनाया गया था। यह इंटरनेट के माध्यम से HTTP का उपयोग करके एक्सेस किए गए इंटरलिंक्ड हाइपरटेक्स्ट दस्तावेज़ों और मल्टीमीडिया संसाधनों का एक विशाल नेटवर्क है।"}},
{type:"mcq",diff:"easy",en:{q:"Who is credited with creating the World Wide Web in 1990?",opts:["Bill Gates","Tim Berners-Lee","Steve Jobs","Charles Babbage"],ans:1,exp:"The World Wide Web was created by physicist Tim Berners-Lee in 1990 at CERN in Geneva. His proposal aimed to allow researchers to work together effectively, eventually evolving into the modern WWW."},hi:{q:"1990 में वर्ल्ड वाइड वेब बनाने का श्रेय किसे दिया जाता है?",opts:["बिल गेट्स","टिम बर्नर्स-ली","स्टीव जॉब्स","चार्ल्स बैबेज"],ans:1,exp:"वर्ल्ड वाइड वेब को 1990 में जिनेवा के सर्न में भौतिक विज्ञानी टिम बर्नर्स-ली द्वारा बनाया गया था। उनके प्रस्ताव का उद्देश्य शोधकर्ताओं को प्रभावी ढंग से एक साथ काम करने की अनुमति देना था, जो अंततः आधुनिक WWW में विकसित हुआ।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following defines a static website?",opts:["It customizes itself frequently","It requires a database for every page","It presents pre-defined, static information to the user","It is not indexed by search engines"],ans:2,exp:"A static website has web pages stored on the server in the exact format sent to the browser. It presents pre-defined, static information consistently without complex backend dynamic processing."},hi:{q:"निम्नलिखित में से कौन एक स्टैटिक वेबसाइट को परिभाषित करता है?",opts:["यह खुद को बार-बार कस्टमाइज़ करता है","इसके हर पेज के लिए डेटाबेस की आवश्यकता होती है","यह उपयोगकर्ता को पूर्व-परिभाषित, स्थिर जानकारी प्रस्तुत करता है","यह खोज इंजनों द्वारा अनुक्रमित नहीं किया जाता है"],ans:2,exp:"एक स्टैटिक वेबसाइट में वेब पेज सर्वर पर उसी प्रारूप में संग्रहीत होते हैं जो ब्राउज़र को भेजे जाते हैं। यह जटिल बैकएंड डायनेमिक प्रोसेसिंग के बिना लगातार पूर्व-परिभाषित, स्थिर जानकारी प्रस्तुत करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does HTML stand for?",opts:["HyperText Markup Language","HyperText Machine Language","HighText Markup Language","Hyper Transfer Markup Language"],ans:0,exp:"HTML stands for HyperText Markup Language. It is the standard language of the web used to define the structure and layout of web pages using specific markup tags."},hi:{q:"HTML का पूर्ण रूप क्या है?",opts:["हाइपरटेक्स्ट मार्कअप लैंग्वेज","हाइपरटेक्स्ट मशीन लैंग्वेज","हाईटेक्स्ट मार्कअप लैंग्वेज","हाइपर ट्रांसफर मार्कअप लैंग्वेज"],ans:0,exp:"HTML का अर्थ हाइपरटेक्स्ट मार्कअप लैंग्वेज है। यह वेब की मानक भाषा है जिसका उपयोग विशिष्ट मार्कअप टैग का उपयोग करके वेब पेजों की संरचना और लेआउट को परिभाषित करने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does XML stand for?",opts:["Extra Markup Language","Extensible Markup Language","Example Markup Language","Executable Markup Language"],ans:1,exp:"XML stands for Extensible Markup Language. It defines a set of rules for encoding documents in a format that is both human-readable and machine-readable, focusing on data structure rather than presentation."},hi:{q:"XML का पूर्ण रूप क्या है?",opts:["एक्स्ट्रा मार्कअप लैंग्वेज","एक्सटेंसिबल मार्कअप लैंग्वेज","एग्जांपल मार्कअप लैंग्वेज","एक्जीक्यूटेबल मार्कअप लैंग्वेज"],ans:1,exp:"XML का अर्थ एक्सटेंसिबल मार्कअप लैंग्वेज है। यह मानव-पठनीय और मशीन-पठनीय दोनों प्रारूपों में दस्तावेज़ों को एनकोड करने के लिए नियमों का एक सेट परिभाषित करता है, जो प्रस्तुति के बजाय डेटा संरचना पर केंद्रित है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag indicates the start of an HTML document?",opts:["<start>","<web>","<html>","<head>"],ans:2,exp:"The <html> tag is the root element of an HTML document. It indicates to the browser that the markup language being used for the enclosed content is HTML."},hi:{q:"कौन सा HTML टैग HTML दस्तावेज़ की शुरुआत को इंगित करता है?",opts:["<start>","<web>","<html>","<head>"],ans:2,exp:"<html> टैग एक HTML दस्तावेज़ का मूल (root) तत्व है। यह ब्राउज़र को इंगित करता है कि संलग्न सामग्री के लिए उपयोग की जा रही मार्कअप भाषा HTML है।"}},
{type:"mcq",diff:"easy",en:{q:"Which part of the HTML document contains metadata and the title?",opts:["<body>","<head>","<meta>","<title>"],ans:1,exp:"The <head> element is a container for all the head elements, such as scripts, style sheets, meta information, and the document title. It is not displayed directly in the browser's viewport."},hi:{q:"HTML दस्तावेज़ के किस भाग में मेटाडेटा और शीर्षक होता है?",opts:["<body>","<head>","<meta>","<title>"],ans:1,exp:"<head> तत्व सभी हेड तत्वों के लिए एक कंटेनर है, जैसे कि स्क्रिप्ट, स्टाइल शीट, मेटा जानकारी और दस्तावेज़ शीर्षक। यह सीधे ब्राउज़र के व्यूपोर्ट में प्रदर्शित नहीं होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to define the title of an HTML document?",opts:["<head>","<title>","<heading>","<h1>"],ans:1,exp:"The <title> tag defines the title of the document, which appears in the browser toolbar, favorites, and search-engine results. It must be placed inside the <head> section."},hi:{q:"HTML दस्तावेज़ के शीर्षक को परिभाषित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<head>","<title>","<heading>","<h1>"],ans:1,exp:"<title> टैग दस्तावेज़ के शीर्षक को परिभाषित करता है, जो ब्राउज़र टूलबार, पसंदीदा (favorites) और खोज-इंजन परिणामों में दिखाई देता है। इसे <head> अनुभाग के अंदर रखा जाना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"How many levels of headings are defined in HTML?",opts:["4 (<h1> to <h4>)","5 (<h1> to <h5>)","6 (<h1> to <h6>)","7 (<h1> to <h7>)"],ans:2,exp:"HTML defines exactly six levels of headings, ranging from <h1> (the most important) down to <h6> (the least important). They help structure the content hierarchically."},hi:{q:"HTML में हेडिंग के कितने स्तर परिभाषित किए गए हैं?",opts:["4 (<h1> से <h4>)","5 (<h1> से <h5>)","6 (<h1> से <h6>)","7 (<h1> से <h7>)"],ans:2,exp:"HTML ठीक छह स्तरों की हेडिंग को परिभाषित करता है, जो <h1> (सबसे महत्वपूर्ण) से लेकर <h6> (सबसे कम महत्वपूर्ण) तक होती है। वे सामग्री को पदानुक्रमित (hierarchically) रूप से संरचित करने में मदद करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is used to define a paragraph?",opts:["<p>","<para>","<pg>","<paragraph>"],ans:0,exp:"The <p> tag is used to define a paragraph in HTML. Browsers automatically add a single blank line before and after each <p> element to separate blocks of text."},hi:{q:"पैराग्राफ को परिभाषित करने के लिए किस HTML टैग का उपयोग किया जाता है?",opts:["<p>","<para>","<pg>","<paragraph>"],ans:0,exp:"HTML में पैराग्राफ को परिभाषित करने के लिए <p> टैग का उपयोग किया जाता है। ब्राउज़र टेक्स्ट के ब्लॉक को अलग करने के लिए स्वचालित रूप से प्रत्येक <p> तत्व से पहले और बाद में एक खाली लाइन जोड़ते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to insert a single line break in HTML?",opts:["<break>","<lb>","<br>","<newline>"],ans:2,exp:"The <br> (or <br /> in XHTML) tag inserts a single line break without starting a new paragraph. It is an empty element, meaning it does not have a closing tag."},hi:{q:"HTML में सिंगल लाइन ब्रेक (line break) डालने के लिए किस टैग का उपयोग किया जाता है?",opts:["<break>","<lb>","<br>","<newline>"],ans:2,exp:"<br> (या XHTML में <br />) टैग नया पैराग्राफ शुरू किए बिना सिंगल लाइन ब्रेक डालता है। यह एक खाली तत्व (empty element) है, जिसका अर्थ है कि इसमें क्लोजिंग टैग नहीं है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following tags makes the enclosed text bold?",opts:["<b>","<bold>","<strong>","<bl>"],ans:0,exp:"The <b> element makes the text bold without adding any extra logical importance. It is a presentational tag used to draw attention to the text visually."},hi:{q:"निम्नलिखित में से कौन सा टैग संलग्न टेक्स्ट को बोल्ड बनाता है?",opts:["<b>","<bold>","<strong>","<bl>"],ans:0,exp:"<b> तत्व बिना कोई अतिरिक्त तार्किक महत्व जोड़े टेक्स्ट को बोल्ड बनाता है। यह एक प्रेजेंटेशनल टैग है जिसका उपयोग दृष्टिगत रूप से टेक्स्ट पर ध्यान आकर्षित करने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to display italicized text?",opts:["<it>","<i>","<italic>","<em>"],ans:1,exp:"The <i> element is used to render the enclosed text in an italicized typeface. It is a presentational HTML tag standard for stylistic emphasis."},hi:{q:"इटैलिकाइज़्ड (तिरछा) टेक्स्ट प्रदर्शित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<it>","<i>","<italic>","<em>"],ans:1,exp:"<i> तत्व का उपयोग संलग्न टेक्स्ट को इटैलिकाइज़्ड टाइपफेस में प्रस्तुत करने के लिए किया जाता है। यह शैलीगत जोर देने के लिए एक मानक प्रेजेंटेशनल HTML टैग है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to display underlined text?",opts:["<ul>","<under>","<u>","<un>"],ans:2,exp:"The <u> element is used to display text with an underline. While standard in older HTML, modern web design often prefers CSS (text-decoration: underline) for this purpose."},hi:{q:"अंडरलाइन टेक्स्ट प्रदर्शित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<ul>","<under>","<u>","<un>"],ans:2,exp:"<u> तत्व का उपयोग अंडरलाइन के साथ टेक्स्ट प्रदर्शित करने के लिए किया जाता है। जबकि पुराने HTML में यह मानक था, आधुनिक वेब डिज़ाइन अक्सर इस उद्देश्य के लिए CSS (text-decoration: underline) पसंद करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag displays text with a strikethrough line?",opts:["<s>","<strike>","<del>","<str>"],ans:1,exp:"The <strike> element displays text with a thin line struck through it. It has been used historically for presentational purposes to indicate deleted or outdated text."},hi:{q:"कौन सा टैग टेक्स्ट के बीच में एक कटी हुई रेखा (strikethrough) प्रदर्शित करता है?",opts:["<s>","<strike>","<del>","<str>"],ans:1,exp:"<strike> तत्व टेक्स्ट को बीच से कटी हुई एक पतली रेखा के साथ प्रदर्शित करता है। ऐतिहासिक रूप से इसका उपयोग प्रेजेंटेशनल उद्देश्यों के लिए हटाए गए या पुराने टेक्स्ट को इंगित करने के लिए किया गया है।"}},
{type:"mcq",diff:"easy",en:{q:"What does CSS stand for in web design?",opts:["Computer Style Sheets","Creative Style Sheets","Cascading Style Sheets","Colorful Style Sheets"],ans:2,exp:"CSS stands for Cascading Style Sheets. It is used alongside HTML to control the look, feel, formatting, and layout of a webpage, separating content from design."},hi:{q:"वेब डिज़ाइन में CSS का पूर्ण रूप क्या है?",opts:["कंप्यूटर स्टाइल शीट्स","क्रिएटिव स्टाइल शीट्स","कास्केडिंग स्टाइल शीट्स","कलरफुल स्टाइल शीट्स"],ans:2,exp:"CSS का अर्थ कास्केडिंग स्टाइल शीट्स है। इसका उपयोग HTML के साथ वेबपेज के रूप, स्वरूपण (formatting) और लेआउट को नियंत्रित करने के लिए किया जाता है, जो सामग्री को डिज़ाइन से अलग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is used to create a hyperlink?",opts:["<link>","<a>","<href>","<hyper>"],ans:1,exp:"The <a> (anchor) tag is used to create a hyperlink in HTML. It uses the 'href' attribute to specify the URL of the destination page or resource."},hi:{q:"हाइपरलिंक बनाने के लिए किस HTML टैग का उपयोग किया जाता है?",opts:["<link>","<a>","<href>","<hyper>"],ans:1,exp:"<a> (एंकर) टैग का उपयोग HTML में हाइपरलिंक बनाने के लिए किया जाता है। यह गंतव्य पृष्ठ या संसाधन का URL निर्दिष्ट करने के लिए 'href' एट्रिब्यूट का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to embed an image in a webpage?",opts:["<image>","<pic>","<img>","<src>"],ans:2,exp:"The <img> tag is used to embed an image. It is an empty element, containing only attributes (like 'src' for the image source and 'alt' for alternate text) and no closing tag."},hi:{q:"वेबपेज में चित्र (image) एम्बेड करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<image>","<pic>","<img>","<src>"],ans:2,exp:"<img> टैग का उपयोग चित्र एम्बेड करने के लिए किया जाता है। यह एक खाली तत्व (empty element) है, जिसमें केवल एट्रिब्यूट होते हैं (जैसे स्रोत के लिए 'src' और वैकल्पिक टेक्स्ट के लिए 'alt') और कोई क्लोजिंग टैग नहीं होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which attribute specifies the path to the image file in the <img> tag?",opts:["path","href","link","src"],ans:3,exp:"The 'src' (source) attribute specifies the URL or file path where the image is stored. The browser uses this attribute to locate and load the image onto the page."},hi:{q:"<img> टैग में कौन सा एट्रिब्यूट चित्र फ़ाइल का पथ (path) निर्दिष्ट करता है?",opts:["path","href","link","src"],ans:3,exp:"'src' (स्रोत) एट्रिब्यूट उस URL या फ़ाइल पथ को निर्दिष्ट करता है जहाँ चित्र संग्रहीत है। ब्राउज़र इस एट्रिब्यूट का उपयोग चित्र का पता लगाने और पृष्ठ पर लोड करने के लिए करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to define an HTML table?",opts:["<tbl>","<table>","<tab>","<grid>"],ans:1,exp:"The <table> tag is used to define a table in HTML. Inside this tag, rows are defined with <tr>, and data cells are defined with <td>."},hi:{q:"HTML टेबल को परिभाषित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<tbl>","<table>","<tab>","<grid>"],ans:1,exp:"<table> टैग का उपयोग HTML में टेबल को परिभाषित करने के लिए किया जाता है। इस टैग के अंदर, पंक्तियों को <tr> के साथ परिभाषित किया जाता है, और डेटा सेल को <td> के साथ परिभाषित किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag defines a row in an HTML table?",opts:["<row>","<table-row>","<tr>","<td>"],ans:2,exp:"The <tr> tag stands for 'table row' and is used to group <td> (table data) or <th> (table header) tags together into a single horizontal row within a <table>."},hi:{q:"HTML टेबल में एक पंक्ति (row) को कौन सा टैग परिभाषित करता है?",opts:["<row>","<table-row>","<tr>","<td>"],ans:2,exp:"<tr> टैग का अर्थ 'टेबल रो' है और इसका उपयोग <table> के भीतर एक एकल क्षैतिज पंक्ति में <td> (टेबल डेटा) या <th> (टेबल हेडर) टैग को एक साथ समूहित करने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag holds the actual content or data inside a table row?",opts:["<tr>","<th>","<td>","<data>"],ans:2,exp:"The <td> tag stands for 'table data' and defines a standard data cell in an HTML table. It holds the text, images, or links that make up the table's content."},hi:{q:"टेबल की पंक्ति के अंदर वास्तविक सामग्री या डेटा कौन सा टैग रखता है?",opts:["<tr>","<th>","<td>","<data>"],ans:2,exp:"<td> टैग का अर्थ 'टेबल डेटा' है और यह HTML टेबल में एक मानक डेटा सेल को परिभाषित करता है। यह उस टेक्स्ट, चित्र या लिंक को रखता है जो टेबल की सामग्री बनाते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to create an unordered list (bullet points)?",opts:["<ol>","<list>","<ul>","<li>"],ans:2,exp:"The <ul> tag defines an unordered list. The list items inside it are typically marked with bullets (small black circles) by default."},hi:{q:"अनऑर्डर्ड सूची (बुलेट पॉइंट) बनाने के लिए किस टैग का उपयोग किया जाता है?",opts:["<ol>","<list>","<ul>","<li>"],ans:2,exp:"<ul> टैग एक अनऑर्डर्ड सूची को परिभाषित करता है। इसके अंदर के सूची आइटम (list items) डिफ़ॉल्ट रूप से बुलेट (छोटे काले घेरे) के साथ चिह्नित होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to create an ordered list (numbered)?",opts:["<ol>","<ul>","<li>","<dl>"],ans:0,exp:"The <ol> tag stands for 'ordered list'. The list items inside it are automatically numbered sequentially by the browser, starting from 1 by default."},hi:{q:"ऑर्डर्ड (क्रमांकित) सूची बनाने के लिए किस टैग का उपयोग किया जाता है?",opts:["<ol>","<ul>","<li>","<dl>"],ans:0,exp:"<ol> टैग का अर्थ 'ऑर्डर्ड लिस्ट' है। इसके अंदर के सूची आइटम ब्राउज़र द्वारा स्वचालित रूप से क्रमिक रूप से गिने जाते हैं, जो डिफ़ॉल्ट रूप से 1 से शुरू होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to define an individual item in a list?",opts:["<item>","<li>","<ol>","<ul>"],ans:1,exp:"The <li> tag defines a 'list item'. It is used inside ordered (<ol>), unordered (<ul>), and directory lists to specify each individual entry."},hi:{q:"सूची में किसी व्यक्तिगत आइटम को परिभाषित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<item>","<li>","<ol>","<ul>"],ans:1,exp:"<li> टैग एक 'लिस्ट आइटम' को परिभाषित करता है। इसका उपयोग ऑर्डर्ड (<ol>), अनऑर्डर्ड (<ul>), और डायरेक्टरी सूचियों के अंदर प्रत्येक व्यक्तिगत प्रविष्टि को निर्दिष्ट करने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is a block-level element commonly used as a container for styling layout?",opts:["<span>","<container>","<div>","<p>"],ans:2,exp:"The <div> tag defines a division or section in an HTML document. It is a block-level element extensively used with CSS for document layout and styling large content blocks."},hi:{q:"कौन सा HTML टैग एक ब्लॉक-लेवल तत्व है जिसका उपयोग आमतौर पर लेआउट को स्टाइल करने के लिए कंटेनर के रूप में किया जाता है?",opts:["<span>","<container>","<div>","<p>"],ans:2,exp:"<div> टैग HTML दस्तावेज़ में एक प्रभाग (division) या अनुभाग को परिभाषित करता है। यह एक ब्लॉक-लेवल तत्व है जिसका बड़े पैमाने पर CSS के साथ दस्तावेज़ लेआउट और बड़े सामग्री ब्लॉकों को स्टाइल करने के लिए उपयोग किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to create an HTML form to pass data to a server?",opts:["<input>","<form>","<data>","<submit>"],ans:1,exp:"The <form> tag is used to create an HTML form for user input. It acts as a container for input elements like text fields, checkboxes, and submit buttons to send data to a server."},hi:{q:"सर्वर पर डेटा पास करने के लिए HTML फॉर्म बनाने के लिए किस टैग का उपयोग किया जाता है?",opts:["<input>","<form>","<data>","<submit>"],ans:1,exp:"उपयोगकर्ता इनपुट के लिए HTML फॉर्म बनाने के लिए <form> टैग का उपयोग किया जाता है। यह सर्वर पर डेटा भेजने के लिए टेक्स्ट फ़ील्ड, चेकबॉक्स और सबमिट बटन जैसे इनपुट तत्वों के लिए एक कंटेनर के रूप में कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does CMS stand for?",opts:["Custom Management System","Content Management System","Code Management System","Creative Markup System"],ans:1,exp:"CMS stands for Content Management System. It is a software application that provides an intuitive user interface for building, editing, and modifying webpage content without extensive coding knowledge."},hi:{q:"CMS का पूर्ण रूप क्या है?",opts:["कस्टम मैनेजमेंट सिस्टम","कंटेंट मैनेजमेंट सिस्टम","कोड मैनेजमेंट सिस्टम","क्रिएटिव मार्कअप सिस्टम"],ans:1,exp:"CMS का अर्थ कंटेंट मैनेजमेंट सिस्टम है। यह एक सॉफ़्टवेयर एप्लिकेशन है जो व्यापक कोडिंग ज्ञान के बिना वेबपेज सामग्री बनाने, संपादित करने और संशोधित करने के लिए एक सहज उपयोगकर्ता इंटरफ़ेस प्रदान करता है।"}},
{type:"tf",diff:"easy",en:{q:"HTML is a programming language used to compile and execute complex software logic.",opts:["True","False"],ans:1,exp:"False. HTML is a markup language, not a programming language. It is used solely to structure and present content on the web using tags, and it lacks compilation, logic loops, or mathematical execution features."},hi:{q:"HTML एक प्रोग्रामिंग भाषा है जिसका उपयोग जटिल सॉफ़्टवेयर लॉजिक को संकलित (compile) और निष्पादित (execute) करने के लिए किया जाता है।",opts:["सही","गलत"],ans:1,exp:"गलत। HTML एक मार्कअप भाषा है, प्रोग्रामिंग भाषा नहीं। इसका उपयोग पूरी तरह से टैग का उपयोग करके वेब पर सामग्री की संरचना और प्रस्तुति के लिए किया जाता है, और इसमें संकलन (compilation), लॉजिक लूप या गणितीय निष्पादन सुविधाओं का अभाव है।"}},
{type:"tf",diff:"easy",en:{q:"The <title> tag should always be placed inside the <body> element of an HTML document.",opts:["True","False"],ans:1,exp:"False. The <title> tag must be placed inside the <head> element. It provides metadata about the document title shown in the browser tab and is not part of the visible page content."},hi:{q:"<title> टैग को हमेशा HTML दस्तावेज़ के <body> तत्व के अंदर रखा जाना चाहिए।",opts:["सही","गलत"],ans:1,exp:"गलत। <title> टैग को <head> तत्व के अंदर रखा जाना चाहिए। यह ब्राउज़र टैब में दिखाए गए दस्तावेज़ शीर्षक के बारे में मेटाडेटा प्रदान करता है और यह दृश्यमान पृष्ठ सामग्री का हिस्सा नहीं है।"}},
{type:"mcq",diff:"medium",en:{q:"Which protocol is primarily used by web browsers and servers to transport web pages?",opts:["FTP","HTTP","SMTP","POP3"],ans:1,exp:"HTTP (HyperText Transfer Protocol) specifies how web browsers and servers communicate. The browser sends an HTTP request, and the server returns the web page using the same protocol."},hi:{q:"वेब पेजों को ट्रांसपोर्ट करने के लिए वेब ब्राउज़र और सर्वर द्वारा मुख्य रूप से किस प्रोटोकॉल का उपयोग किया जाता है?",opts:["FTP","HTTP","SMTP","POP3"],ans:1,exp:"HTTP (हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल) यह निर्दिष्ट करता है कि वेब ब्राउज़र और सर्वर कैसे संवाद करते हैं। ब्राउज़र एक HTTP अनुरोध भेजता है, और सर्वर उसी प्रोटोकॉल का उपयोग करके वेब पेज लौटाता है।"}},
{type:"mcq",diff:"medium",en:{q:"According to the text, which of the following is one of the four main parts of DHTML?",opts:["PHP Scripting","MySQL Database","Document Object Model (DOM)","Apache Server"],ans:2,exp:"The four parts of DHTML are the Document Object Model (DOM), Scripts (like JavaScript), Cascading Style Sheets (CSS), and XHTML. The DOM allows access to and manipulation of any part of a Web page."},hi:{q:"पाठ के अनुसार, निम्नलिखित में से कौन सा DHTML के चार मुख्य भागों में से एक है?",opts:["PHP स्क्रिप्टिंग","MySQL डेटाबेस","डॉक्यूमेंट ऑब्जेक्ट मॉडल (DOM)","अपाचे सर्वर"],ans:2,exp:"DHTML के चार भाग डॉक्यूमेंट ऑब्जेक्ट मॉडल (DOM), स्क्रिप्ट (जैसे जावास्क्रिप्ट), कास्केडिंग स्टाइल शीट्स (CSS) और XHTML हैं। DOM वेब पेज के किसी भी हिस्से तक पहुंचने और हेरफेर करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the purpose of the <!DOCTYPE> declaration?",opts:["It defines the CSS styles","It connects to a database","It informs the browser about the exact HTML version used","It executes JavaScript"],ans:2,exp:"The <!DOCTYPE> declaration is not an HTML tag but an instruction to the web browser about what version of HTML the page is written in, ensuring the document is displayed correctly."},hi:{q:"<!DOCTYPE> डिक्लेरेशन का उद्देश्य क्या है?",opts:["यह CSS स्टाइल को परिभाषित करता है","यह डेटाबेस से जुड़ता है","यह ब्राउज़र को उपयोग किए गए सटीक HTML संस्करण के बारे में सूचित करता है","यह जावास्क्रिप्ट निष्पादित करता है"],ans:2,exp:"<!DOCTYPE> डिक्लेरेशन कोई HTML टैग नहीं है, बल्कि वेब ब्राउज़र को यह निर्देश है कि पेज HTML के किस संस्करण में लिखा गया है, यह सुनिश्चित करते हुए कि दस्तावेज़ सही ढंग से प्रदर्शित हो।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following tags is NOT an empty element?",opts:["<br>","<hr>","<img>","<p>"],ans:3,exp:"Empty elements do not require closing tags because they cannot contain content. <br>, <hr>, and <img> are empty elements, whereas <p> is a container that requires a closing </p> tag."},hi:{q:"निम्नलिखित में से कौन सा टैग एक खाली तत्व (empty element) नहीं है?",opts:["<br>","<hr>","<img>","<p>"],ans:3,exp:"खाली तत्वों (empty elements) को क्लोजिंग टैग की आवश्यकता नहीं होती है क्योंकि उनमें सामग्री नहीं हो सकती है। <br>, <hr>, और <img> खाली तत्व हैं, जबकि <p> एक कंटेनर है जिसके लिए क्लोजिंग </p> टैग की आवश्यकता होती है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag preserves the exact whitespace and formatting of the source text when displayed?",opts:["<code>","<pre>","<blockquote>","<samp>"],ans:1,exp:"The <pre> (preformatted text) tag displays text exactly as it is written in the HTML source code, preserving spaces and line breaks. The text is usually rendered in a monospaced font."},hi:{q:"प्रदर्शित होने पर कौन सा टैग स्रोत टेक्स्ट के सटीक व्हाइटस्पेस और स्वरूपण (formatting) को सुरक्षित रखता है?",opts:["<code>","<pre>","<blockquote>","<samp>"],ans:1,exp:"<pre> (प्रीफॉर्मेटेड टेक्स्ट) टैग टेक्स्ट को ठीक वैसे ही प्रदर्शित करता है जैसे वह HTML स्रोत कोड में लिखा गया है, जिसमें स्पेस और लाइन ब्रेक संरक्षित रहते हैं। टेक्स्ट को आमतौर पर मोनोस्पेस्ड फ़ॉन्ट में रेंडर किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag is used to display text half a character's height above the surrounding text?",opts:["<top>","<up>","<sup>","<high>"],ans:2,exp:"The <sup> element is used to render superscript text, which is displayed half a character's height above the baseline. It is useful for mathematical exponents or ordinal numbers like 1st."},hi:{q:"आसपास के टेक्स्ट के ऊपर आधे अक्षर की ऊंचाई पर टेक्स्ट प्रदर्शित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<top>","<up>","<sup>","<high>"],ans:2,exp:"<sup> तत्व का उपयोग सुपरस्क्रिप्ट टेक्स्ट को प्रस्तुत करने के लिए किया जाता है, जो बेसलाइन से आधे अक्षर की ऊंचाई पर प्रदर्शित होता है। यह गणितीय घातांक या 1st जैसे क्रमसूचक संख्याओं के लिए उपयोगी है।"}},
{type:"mcq",diff:"medium",en:{q:"Using the <style> element within the <head> section is an example of which CSS inclusion method?",opts:["Inline CSS","Internal CSS","External CSS","Imported CSS"],ans:1,exp:"Internal CSS involves placing all CSS rules inside a <style> element within the HTML document's <head> section. It applies styles to that single specific document."},hi:{q:"<head> अनुभाग के भीतर <style> तत्व का उपयोग करना किस CSS समावेशन विधि का उदाहरण है?",opts:["इनलाइन CSS","इंटरनल CSS","एक्सटर्नल CSS","इम्पोर्टेड CSS"],ans:1,exp:"इंटरनल (Internal) CSS में HTML दस्तावेज़ के <head> अनुभाग के भीतर एक <style> तत्व के अंदर सभी CSS नियम रखना शामिल है। यह उस एकल विशिष्ट दस्तावेज़ पर स्टाइल लागू करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the correct HTML syntax for creating a hyperlink?",opts:["<link href='url'>Text</link>","<a href='url'>Link text</a>","<a target='url'>Link text</a>","<hyper url='url'>Text</hyper>"],ans:1,exp:"The correct syntax uses the anchor <a> tag with the 'href' attribute to define the destination URL, wrapping the clickable link text. Example: <a href='http://example.com'>Link text</a>."},hi:{q:"हाइपरलिंक बनाने के लिए सही HTML सिंटैक्स क्या है?",opts:["<link href='url'>Text</link>","<a href='url'>Link text</a>","<a target='url'>Link text</a>","<hyper url='url'>Text</hyper>"],ans:1,exp:"सही सिंटैक्स गंतव्य URL को परिभाषित करने के लिए 'href' एट्रिब्यूट के साथ एंकर <a> टैग का उपयोग करता है, जो क्लिक करने योग्य लिंक टेक्स्ट को लपेटता है। उदाहरण: <a href='http://example.com'>लिंक टेक्स्ट</a>।"}},
{type:"mcq",diff:"medium",en:{q:"Which attribute specifies where to open the linked document in an <a> tag?",opts:["href","src","target","window"],ans:2,exp:"The 'target' attribute tells the browser where to open the linked document. It can open the link in the same frame, a new window, or a specific iframe."},hi:{q:"कौन सा एट्रिब्यूट निर्दिष्ट करता है कि <a> टैग में लिंक किए गए दस्तावेज़ को कहाँ खोलना है?",opts:["href","src","target","window"],ans:2,exp:"'target' एट्रिब्यूट ब्राउज़र को बताता है कि लिंक किए गए दस्तावेज़ को कहाँ खोलना है। यह लिंक को उसी फ़्रेम, नई विंडो या किसी विशिष्ट आईफ्रेम (iframe) में खोल सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Setting the target attribute of a link to '_blank' achieves what result?",opts:["Opens the link in the same window","Opens the link in a new browser window or tab","Opens the link in a popup dialog","Downloads the linked document"],ans:1,exp:"When the target attribute is set to '_blank' (target=\"_blank\"), the browser forces the linked document to open in a completely new browser window or new tab."},hi:{q:"लिंक के टारगेट (target) एट्रिब्यूट को '_blank' पर सेट करने से क्या परिणाम प्राप्त होता है?",opts:["उसी विंडो में लिंक खोलता है","एक नई ब्राउज़र विंडो या टैब में लिंक खोलता है","एक पॉपअप डायलॉग में लिंक खोलता है","लिंक किए गए दस्तावेज़ को डाउनलोड करता है"],ans:1,exp:"जब लक्ष्य एट्रिब्यूट '_blank' (target=\"_blank\") पर सेट होता है, तो ब्राउज़र लिंक किए गए दस्तावेज़ को पूरी तरह से नई ब्राउज़र विंडो या नए टैब में खोलने के लिए बाध्य करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the purpose of the 'alt' attribute in an <img> tag?",opts:["To set the image alignment","To define an alternate text if the image cannot be displayed","To create an alert box when clicked","To specify the image's URL"],ans:1,exp:"The 'alt' attribute provides alternative text describing the image. This text is displayed if the image fails to load, and it is crucial for screen readers used by visually impaired users."},hi:{q:"<img> टैग में 'alt' एट्रिब्यूट का उद्देश्य क्या है?",opts:["चित्र संरेखण (alignment) सेट करने के लिए","यदि चित्र प्रदर्शित नहीं किया जा सकता है तो वैकल्पिक टेक्स्ट परिभाषित करने के लिए","क्लिक करने पर एक अलर्ट बॉक्स बनाने के लिए","चित्र का URL निर्दिष्ट करने के लिए"],ans:1,exp:"'alt' एट्रिब्यूट चित्र का वर्णन करने वाला वैकल्पिक टेक्स्ट प्रदान करता है। यदि चित्र लोड होने में विफल रहता है तो यह टेक्स्ट प्रदर्शित होता है, और यह दृष्टिबाधित उपयोगकर्ताओं द्वारा उपयोग किए जाने वाले स्क्रीन रीडर के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag defines header information inside an HTML table?",opts:["<head>","<theader>","<th>","<tr>"],ans:2,exp:"The <th> tag defines a header cell in an HTML table. Browsers typically render the text within a <th> element as bold and centered by default to distinguish it from standard <td> data cells."},hi:{q:"कौन सा टैग HTML टेबल के अंदर हेडर जानकारी को परिभाषित करता है?",opts:["<head>","<theader>","<th>","<tr>"],ans:2,exp:"<th> टैग HTML टेबल में हेडर सेल को परिभाषित करता है। मानक <td> डेटा सेल से इसे अलग करने के लिए ब्राउज़र आमतौर पर <th> तत्व के भीतर टेक्स्ट को बोल्ड और डिफ़ॉल्ट रूप से केंद्रित (centered) के रूप में प्रस्तुत करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag is used in conjunction with <dt> and <dd> to create a definition list?",opts:["<ul>","<ol>","<dl>","<list>"],ans:2,exp:"The <dl> tag defines a definition list. It contains <dt> tags for the terms being defined and <dd> tags for the description or definition of those terms."},hi:{q:"परिभाषा सूची (definition list) बनाने के लिए <dt> और <dd> के साथ किस टैग का उपयोग किया जाता है?",opts:["<ul>","<ol>","<dl>","<list>"],ans:2,exp:"<dl> टैग एक परिभाषा सूची को परिभाषित करता है। इसमें परिभाषित किए जा रहे शब्दों के लिए <dt> टैग और उन शब्दों के विवरण या परिभाषा के लिए <dd> टैग शामिल हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is an example of an HTML inline element?",opts:["<div>","<h1>","<table>","<span>"],ans:3,exp:"The <span> element is an inline container used for text styling. Unlike block-level elements (div, h1, table) which start on a new line, inline elements flow within the surrounding text."},hi:{q:"निम्नलिखित में से कौन सा HTML इनलाइन (inline) तत्व का उदाहरण है?",opts:["<div>","<h1>","<table>","<span>"],ans:3,exp:"<span> तत्व एक इनलाइन कंटेनर है जिसका उपयोग टेक्स्ट स्टाइलिंग के लिए किया जाता है। ब्लॉक-लेवल तत्वों (div, h1, table) के विपरीत जो एक नई लाइन पर शुरू होते हैं, इनलाइन तत्व आसपास के टेक्स्ट के भीतर प्रवाहित होते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which input type defines a one-line text field in an HTML form?",opts:["<input type='textfield'>","<input type='text'>","<input type='string'>","<input type='char'>"],ans:1,exp:"The <input type=\"text\"> defines a standard one-line input field where users can type alphanumeric characters. By default, it usually has a width of 20 characters."},hi:{q:"कौन सा इनपुट प्रकार HTML फॉर्म में एक-पंक्ति टेक्स्ट फ़ील्ड (one-line text field) को परिभाषित करता है?",opts:["<input type='textfield'>","<input type='text'>","<input type='string'>","<input type='char'>"],ans:1,exp:"<input type=\"text\"> एक मानक एक-पंक्ति इनपुट फ़ील्ड को परिभाषित करता है जहाँ उपयोगकर्ता अल्फ़ान्यूमेरिक वर्ण टाइप कर सकते हैं। डिफ़ॉल्ट रूप से, इसकी चौड़ाई आमतौर पर 20 वर्णों की होती है।"}},
{type:"mcq",diff:"medium",en:{q:"Which form input type allows the user to select ONLY ONE option from a limited number of choices?",opts:["checkbox","radio","select","button"],ans:1,exp:"The <input type=\"radio\"> defines a radio button. When multiple radio buttons share the same 'name' attribute, they form a group where only one button can be selected at a time."},hi:{q:"कौन सा फॉर्म इनपुट प्रकार उपयोगकर्ता को सीमित विकल्पों में से केवल एक विकल्प चुनने की अनुमति देता है?",opts:["चेकबॉक्स (checkbox)","रेडियो (radio)","सिलेक्ट (select)","बटन (button)"],ans:1,exp:"<input type=\"radio\"> एक रेडियो बटन को परिभाषित करता है। जब कई रेडियो बटन एक ही 'name' एट्रिब्यूट साझा करते हैं, तो वे एक समूह बनाते हैं जहाँ एक बार में केवल एक बटन का चयन किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which form input type allows the user to select ONE or MORE options from a set?",opts:["radio","checkbox","text","password"],ans:1,exp:"The <input type=\"checkbox\"> defines a checkbox. Checkboxes act independently, allowing the user to check multiple boxes to select multiple desired options from a provided list."},hi:{q:"कौन सा फॉर्म इनपुट प्रकार उपयोगकर्ता को एक सेट से एक या अधिक (ONE or MORE) विकल्पों का चयन करने की अनुमति देता है?",opts:["रेडियो (radio)","चेकबॉक्स (checkbox)","टेक्स्ट (text)","पासवर्ड (password)"],ans:1,exp:"<input type=\"checkbox\"> एक चेकबॉक्स को परिभाषित करता है। चेकबॉक्स स्वतंत्र रूप से कार्य करते हैं, जिससे उपयोगकर्ता दी गई सूची से कई वांछित विकल्पों का चयन करने के लिए कई बॉक्स चेक कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag defines an inline sub window (frame) to embed another webpage within the current page?",opts:["<frame>","<window>","<embed>","<iframe>"],ans:3,exp:"The <iframe> tag stands for inline frame. It is used to embed a separate HTML document or webpage directly into the current HTML document, specifying the source using the 'src' attribute."},hi:{q:"वर्तमान पृष्ठ के भीतर किसी अन्य वेबपेज को एम्बेड करने के लिए कौन सा टैग एक इनलाइन सब विंडो (फ़्रेम) को परिभाषित करता है?",opts:["<frame>","<window>","<embed>","<iframe>"],ans:3,exp:"<iframe> टैग का अर्थ इनलाइन फ़्रेम है। इसका उपयोग एक अलग HTML दस्तावेज़ या वेबपेज को सीधे वर्तमान HTML दस्तावेज़ में एम्बेड करने के लिए किया जाता है, 'src' एट्रिब्यूट का उपयोग करके स्रोत निर्दिष्ट किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"How are HTML colors defined using HEX notation?",opts:["Using 3 pairs of two-digit numbers starting with #","Using RGB functions","Using standard color names only","Using 4-digit binary codes"],ans:0,exp:"In HTML, HEX colors are defined using a '#' followed by 3 pairs of two-digit hexadecimal numbers (representing Red, Green, and Blue values), such as #FF0000 for pure red."},hi:{q:"HEX नोटेशन का उपयोग करके HTML रंगों को कैसे परिभाषित किया जाता है?",opts:["# से शुरू होने वाले दो-अंकीय संख्याओं के 3 जोड़े का उपयोग करके","RGB फ़ंक्शंस का उपयोग करके","केवल मानक रंग नामों का उपयोग करके","4-अंकीय बाइनरी कोड का उपयोग करके"],ans:0,exp:"HTML में, HEX रंगों को '#' के बाद दो-अंकीय हेक्साडेसिमल संख्याओं (लाल, हरे और नीले मूल्यों का प्रतिनिधित्व करते हुए) के 3 जोड़े का उपयोग करके परिभाषित किया जाता है, जैसे शुद्ध लाल के लिए #FF0000।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag is used to define a client-side script, such as JavaScript, in an HTML document?",opts:["<code>","<javascript>","<script>","<client>"],ans:2,exp:"The <script> tag is used to embed or reference executable client-side scripts. It can contain inline code or point to an external file using the 'src' attribute."},hi:{q:"HTML दस्तावेज़ में क्लाइंट-साइड स्क्रिप्ट, जैसे जावास्क्रिप्ट, को परिभाषित करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<code>","<javascript>","<script>","<client>"],ans:2,exp:"<script> टैग का उपयोग निष्पादन योग्य क्लाइंट-साइड स्क्रिप्ट को एम्बेड या संदर्भित करने के लिए किया जाता है। इसमें इनलाइन कोड हो सकता है या 'src' एट्रिब्यूट का उपयोग करके बाहरी फ़ाइल को इंगित कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag provides alternate content for users whose browsers do not support client-side scripts?",opts:["<nojs>","<noscript>","<altscript>","<error>"],ans:1,exp:"The <noscript> tag is a fallback mechanism. The content inside this tag is displayed only if the user's browser does not support JavaScript or has scripting explicitly disabled."},hi:{q:"कौन सा टैग उन उपयोगकर्ताओं के लिए वैकल्पिक सामग्री प्रदान करता है जिनके ब्राउज़र क्लाइंट-साइड स्क्रिप्ट का समर्थन नहीं करते हैं?",opts:["<nojs>","<noscript>","<altscript>","<error>"],ans:1,exp:"<noscript> टैग एक फॉलबैक तंत्र है। इस टैग के अंदर की सामग्री केवल तभी प्रदर्शित होती है जब उपयोगकर्ता का ब्राउज़र जावास्क्रिप्ट का समर्थन नहीं करता है या स्क्रिप्टिंग स्पष्ट रूप से अक्षम (disabled) है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the correct HTML character entity to insert a non-breaking space?",opts:["&space;","&blank;","&nbsp;","&nsp;"],ans:2,exp:"The entity &nbsp; stands for 'non-breaking space'. Because browsers truncate multiple spaces into one, &nbsp; must be used to force the rendering of additional continuous spaces."},hi:{q:"नॉन-ब्रेकिंग स्पेस डालने के लिए सही HTML कैरेक्टर एंटिटी क्या है?",opts:["&space;","&blank;","&nbsp;","&nsp;"],ans:2,exp:"एंटिटी &nbsp; का अर्थ 'नॉन-ब्रेकिंग स्पेस' है। क्योंकि ब्राउज़र कई रिक्त स्थानों (spaces) को एक में काट देते हैं, अतिरिक्त निरंतर रिक्त स्थान के प्रतिपादन को बाध्य करने के लिए &nbsp; का उपयोग किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"In a URL structure like 'http://www.w3schools.com', what does 'www' represent?",opts:["Scheme","Host","Path","Filename"],ans:1,exp:"In the URL structure, 'http' is the scheme, 'www' is the default domain host, and 'w3schools.com' is the domain name. The host directs traffic to the correct web server."},hi:{q:"'http://www.w3schools.com' जैसी URL संरचना में, 'www' क्या दर्शाता है?",opts:["स्कीम (Scheme)","होस्ट (Host)","पथ (Path)","फ़ाइल का नाम (Filename)"],ans:1,exp:"URL संरचना में, 'http' स्कीम है, 'www' डिफ़ॉल्ट डोमेन होस्ट है, और 'w3schools.com' डोमेन नाम है। होस्ट ट्रैफ़िक को सही वेब सर्वर तक निर्देशित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"How does URL encoding normally handle space characters in a URL?",opts:["Replaces them with an underscore (_)","Replaces them with a plus sign (+) or %20","Deletes them entirely","Leaves them as spaces"],ans:1,exp:"URLs cannot contain spaces because they must be transmitted over the Internet using valid ASCII formats. URL encoding replaces spaces with a plus sign (+) or the hexadecimal equivalent %20."},hi:{q:"URL एन्कोडिंग सामान्यतः URL में स्पेस वर्णों (space characters) को कैसे संभालता है?",opts:["उन्हें अंडरस्कोर (_) से बदल देता है","उन्हें प्लस चिह्न (+) या %20 से बदल देता है","उन्हें पूरी तरह से हटा देता है","उन्हें स्पेस के रूप में ही छोड़ देता है"],ans:1,exp:"URL में स्पेस नहीं हो सकते क्योंकि उन्हें मान्य ASCII प्रारूपों का उपयोग करके इंटरनेट पर प्रेषित किया जाना चाहिए। URL एन्कोडिंग रिक्त स्थानों को प्लस चिह्न (+) या हेक्साडेसिमल समकक्ष %20 से बदल देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is a popular free web software designed for creating template-based websites or blogs?",opts:["Photoshop","WordPress","AutoCAD","KompoZer"],ans:1,exp:"WordPress is a highly popular, free, open-source Content Management System (CMS) that simplifies the creation and maintenance of template-based websites and blogs."},hi:{q:"निम्नलिखित में से कौन सा टेम्प्लेट-आधारित वेबसाइट या ब्लॉग बनाने के लिए डिज़ाइन किया गया एक लोकप्रिय मुफ़्त वेब सॉफ़्टवेयर है?",opts:["फोटोशॉप (Photoshop)","वर्डप्रेस (WordPress)","ऑटोकैड (AutoCAD)","कोम्पोजर (KompoZer)"],ans:1,exp:"वर्डप्रेस एक अत्यधिक लोकप्रिय, मुफ़्त, ओपन-सोर्स कंटेंट मैनेजमेंट सिस्टम (CMS) है जो टेम्प्लेट-आधारित वेबसाइटों और ब्लॉगों के निर्माण और रखरखाव को सरल बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the acronym WYSIWYG stand for in web authoring tools?",opts:["What You See Is What You Get","Where You Style Is Where You Go","Web Yields Simple Internet Web Yields Go","What You Say Is What You Generate"],ans:0,exp:"WYSIWYG stands for 'What You See Is What You Get'. These editors allow developers to see the final layout of the webpage visually as they design it, rather than just writing raw source code."},hi:{q:"वेब ऑथरिंग टूल्स में WYSIWYG का पूर्ण रूप क्या है?",opts:["वॉट यू सी इज व्हाट यू गेट (What You See Is What You Get)","वेयर यू स्टाइल इज वेयर यू गो","वेब यील्ड्स सिंपल इंटरनेट वेब यील्ड्स गो","वॉट यू से इज वॉट यू जनरेट"],ans:0,exp:"WYSIWYG का अर्थ 'वॉट यू सी इज व्हाट यू गेट' है। ये संपादक डेवलपर्स को केवल कच्चे स्रोत कोड लिखने के बजाय डिज़ाइन करते समय वेबपेज के अंतिम लेआउट को दृष्टिगत रूप से देखने की अनुमति देते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What type of software is KompoZer?",opts:["An antivirus program","A WYSIWYG Web Authoring System","A database management system","A web browser"],ans:1,exp:"KompoZer is a complete Web Authoring System that provides easy-to-use WYSIWYG web page editing capabilities, allowing users to create sites without technical HTML expertise."},hi:{q:"कोम्पोजर (KompoZer) किस प्रकार का सॉफ्टवेयर है?",opts:["एक एंटीवायरस प्रोग्राम","एक WYSIWYG वेब ऑथरिंग सिस्टम","एक डेटाबेस प्रबंधन प्रणाली","एक वेब ब्राउज़र"],ans:1,exp:"कोम्पोजर एक संपूर्ण वेब ऑथरिंग सिस्टम है जो उपयोग में आसान WYSIWYG वेब पेज संपादन क्षमताएं प्रदान करता है, जिससे उपयोगकर्ता तकनीकी HTML विशेषज्ञता के बिना साइट बना सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In KompoZer, which toolbar allows you to apply paragraph formats, change fonts, and justify text?",opts:["Composition Toolbar","Status Toolbar","Format Toolbar","Edit Mode Toolbar"],ans:2,exp:"The Format Toolbar in KompoZer provides styling options. You can use it to change fonts, apply text colors, adjust sizing, create lists, and set text alignment (left, center, right)."},hi:{q:"कोम्पोजर में, कौन सा टूलबार आपको पैराग्राफ प्रारूप लागू करने, फ़ॉन्ट बदलने और टेक्स्ट को जस्टिफाई करने की अनुमति देता है?",opts:["कम्पोजीशन टूलबार","स्टेटस टूलबार","फॉर्मेट टूलबार","एडिट मोड टूलबार"],ans:2,exp:"कोम्पोजर में फॉर्मेट टूलबार स्टाइलिंग विकल्प प्रदान करता है। आप इसका उपयोग फ़ॉन्ट बदलने, टेक्स्ट रंग लागू करने, आकार समायोजित करने, सूची बनाने और टेक्स्ट संरेखण (बाएं, केंद्र, दाएं) सेट करने के लिए कर सकते हैं।"}},
{type:"tf",diff:"medium",en:{q:"An inline HTML element, such as <span> or <a>, normally forces a line break and starts on a new line when displayed.",opts:["True","False"],ans:1,exp:"False. Inline elements flow along with the surrounding text without forcing a line break. Block-level elements (like <div> or <p>) are the ones that normally start and end with a new line."},hi:{q:"एक इनलाइन HTML तत्व, जैसे <span> या <a>, सामान्यतः एक लाइन ब्रेक को बाध्य करता है और प्रदर्शित होने पर एक नई लाइन पर शुरू होता है।",opts:["सही","गलत"],ans:1,exp:"गलत। इनलाइन तत्व लाइन ब्रेक के बिना आसपास के टेक्स्ट के साथ प्रवाहित होते हैं। ब्लॉक-लेवल तत्व (जैसे <div> या <p>) वे होते हैं जो सामान्यतः एक नई लाइन के साथ शुरू और समाप्त होते हैं।"}},
{type:"tf",diff:"medium",en:{q:"The <input type=\"submit\"> tag defines a button specifically designed to send form data to a server.",opts:["True","False"],ans:0,exp:"True. Defining an input with type=\"submit\" creates a clickable submit button. Upon clicking, it automatically gathers the form data and sends it to the URL specified in the form's action attribute."},hi:{q:"<input type=\"submit\"> टैग विशेष रूप से सर्वर पर फॉर्म डेटा भेजने के लिए डिज़ाइन किए गए बटन को परिभाषित करता है।",opts:["सही","गलत"],ans:0,exp:"सही। type=\"submit\" के साथ इनपुट को परिभाषित करने से एक क्लिक करने योग्य सबमिट बटन बनता है। क्लिक करने पर, यह स्वचालित रूप से फॉर्म डेटा एकत्र करता है और इसे फॉर्म के एक्शन एट्रिब्यूट में निर्दिष्ट URL पर भेजता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which HTML attribute is used to apply inline CSS styles directly to a specific element?",opts:["class","style","css","design"],ans:1,exp:"Inline CSS is applied using the 'style' attribute directly within an HTML element's start tag. This method overrides internal and external stylesheets for that specific element."},hi:{q:"किसी विशिष्ट तत्व पर सीधे इनलाइन CSS स्टाइल लागू करने के लिए किस HTML एट्रिब्यूट का उपयोग किया जाता है?",opts:["class","style","css","design"],ans:1,exp:"इनलाइन CSS को 'style' एट्रिब्यूट का उपयोग करके सीधे HTML तत्व के स्टार्ट टैग के भीतर लागू किया जाता है। यह विधि उस विशिष्ट तत्व के लिए आंतरिक (internal) और बाहरी (external) स्टाइलशीट को ओवरराइड करती है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the correct syntax for applying a background color using inline CSS to a <body> tag?",opts:["<body style='background-color:PowderBlue;'>","<body color='PowderBlue'>","<body bg='PowderBlue'>","<body style='bg-color:PowderBlue;'>"],ans:0,exp:"The correct inline CSS syntax assigns property-value pairs inside the style attribute. For background colors, it is style=\"background-color:Value;\". Example: <body style=\"background-color:PowderBlue;\">."},hi:{q:"<body> टैग पर इनलाइन CSS का उपयोग करके पृष्ठभूमि रंग (background color) लागू करने के लिए सही सिंटैक्स क्या है?",opts:["<body style='background-color:PowderBlue;'>","<body color='PowderBlue'>","<body bg='PowderBlue'>","<body style='bg-color:PowderBlue;'>"],ans:0,exp:"सही इनलाइन CSS सिंटैक्स स्टाइल एट्रिब्यूट के अंदर प्रॉपर्टी-वैल्यू जोड़े (pairs) निर्दिष्ट करता है। पृष्ठभूमि रंगों के लिए, यह style=\"background-color:Value;\" है। उदाहरण: <body style=\"background-color:PowderBlue;\">।"}},
{type:"mcq",diff:"hard",en:{q:"In the context of DHTML, what does DOM stand for?",opts:["Data Object Model","Document Object Model","Dynamic Output Markup","Digital Object Module"],ans:1,exp:"DOM stands for Document Object Model. It defines the logical structure of web documents and dictates how they are accessed and manipulated by scripting languages like JavaScript in DHTML."},hi:{q:"DHTML के संदर्भ में, DOM का पूर्ण रूप क्या है?",opts:["डेटा ऑब्जेक्ट मॉडल","डॉक्यूमेंट ऑब्जेक्ट मॉडल","डायनेमिक आउटपुट मार्कअप","डिजिटल ऑब्जेक्ट मॉड्यूल"],ans:1,exp:"DOM का अर्थ डॉक्यूमेंट ऑब्जेक्ट मॉडल है। यह वेब दस्तावेज़ों की तार्किक संरचना को परिभाषित करता है और यह निर्धारित करता है कि DHTML में जावास्क्रिप्ट जैसी स्क्रिप्टिंग भाषाओं द्वारा उन तक कैसे पहुँचा जाए और उनमें हेरफेर किया जाए।"}},
{type:"mcq",diff:"hard",en:{q:"Which tag defines the actual term being defined inside a <dl> (definition list) block?",opts:["<dl>","<dd>","<dt>","<li>"],ans:2,exp:"Inside a Definition List (<dl>), the <dt> tag defines the term (item), and the <dd> tag defines the description or the definition corresponding to that term."},hi:{q:"कौन सा टैग <dl> (परिभाषा सूची) ब्लॉक के अंदर परिभाषित किए जा रहे वास्तविक शब्द (term) को परिभाषित करता है?",opts:["<dl>","<dd>","<dt>","<li>"],ans:2,exp:"डेफिनेशन लिस्ट (<dl>) के अंदर, <dt> टैग शब्द (आइटम) को परिभाषित करता है, और <dd> टैग उस शब्द के अनुरूप विवरण या परिभाषा को परिभाषित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"According to the DHTML structure, which of the following is NOT a primary feature of DHTML?",opts:["Changing tags and properties","Real-time positioning","Executing backend SQL Queries","Dynamic fonts"],ans:2,exp:"Executing backend SQL Queries is a server-side operation. DHTML operates on the client-side, featuring tag changing, real-time positioning, dynamic fonts, and data binding."},hi:{q:"DHTML संरचना के अनुसार, निम्नलिखित में से कौन सी DHTML की प्राथमिक विशेषता नहीं है?",opts:["टैग और प्रॉपर्टीज बदलना","रीयल-टाइम पोजिशनिंग","बैकएंड SQL क्वेरीज़ निष्पादित करना","डायनेमिक फ़ॉन्ट्स"],ans:2,exp:"बैकएंड SQL क्वेरीज़ को निष्पादित करना एक सर्वर-साइड ऑपरेशन है। DHTML क्लाइंट-साइड पर काम करता है, जिसमें टैग बदलना, रीयल-टाइम पोजिशनिंग, डायनेमिक फ़ॉन्ट और डेटा बाइंडिंग शामिल हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which HTML tag applies a monospaced font where every character has the exact same width?",opts:["<mono>","<fixed>","<tt>","<pre>"],ans:2,exp:"The <tt> (Teletype text) element renders content in a fixed-width, monospaced font. Unlike variable-width fonts, each character (like 'm' or 'i') takes up the same horizontal space."},hi:{q:"कौन सा HTML टैग मोनोस्पेस्ड फ़ॉन्ट लागू करता है जहाँ प्रत्येक वर्ण की चौड़ाई बिल्कुल समान होती है?",opts:["<mono>","<fixed>","<tt>","<pre>"],ans:2,exp:"<tt> (टेलीटाइप टेक्स्ट) तत्व सामग्री को एक निश्चित-चौड़ाई, मोनोस्पेस्ड फ़ॉन्ट में प्रस्तुत करता है। परिवर्तनीय-चौड़ाई (variable-width) वाले फ़ॉन्ट के विपरीत, प्रत्येक वर्ण (जैसे 'm' या 'i') समान क्षैतिज स्थान लेता है।"}},
{type:"mcq",diff:"hard",en:{q:"How do you explicitly remove the border around an iframe using HTML attributes?",opts:["border='none'","frameborder='0'","border='0'","style='noborder'"],ans:1,exp:"The 'frameborder' attribute specifies whether or not to display a border around an iframe. Setting it to \"0\" (frameborder=\"0\") completely removes the default browser border."},hi:{q:"HTML एट्रिब्यूट्स का उपयोग करके आप स्पष्ट रूप से आईफ्रेम (iframe) के चारों ओर की सीमा (border) को कैसे हटाते हैं?",opts:["border='none'","frameborder='0'","border='0'","style='noborder'"],ans:1,exp:"'frameborder' एट्रिब्यूट निर्दिष्ट करता है कि iframe के चारों ओर बॉर्डर प्रदर्शित करना है या नहीं। इसे \"0\" (frameborder=\"0\") पर सेट करने से डिफ़ॉल्ट ब्राउज़र बॉर्डर पूरी तरह से हट जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the highest possible hexadecimal value that can be assigned to an RGB light source in HTML?",opts:["100","255","FF","GG"],ans:2,exp:"In HTML HEX color codes, the highest value for a single color channel (R, G, or B) is 255 in decimal, which is 'FF' in hexadecimal notation. The lowest is '00'."},hi:{q:"HTML में RGB प्रकाश स्रोत को सौंपा जा सकने वाला उच्चतम संभावित हेक्साडेसिमल मान क्या है?",opts:["100","255","FF","GG"],ans:2,exp:"HTML HEX कलर कोड में, सिंगल कलर चैनल (R, G, या B) के लिए उच्चतम मान दशमलव (decimal) में 255 है, जो हेक्साडेसिमल नोटेशन में 'FF' है। सबसे कम '00' है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the precise HEX color code for pure red?",opts:["#FF0000","#00FF00","#0000FF","#FFFFFF"],ans:0,exp:"HEX colors follow the #RRGGBB format. Pure red maximizes the red channel (FF) and turns off green and blue (00), resulting in the code #FF0000."},hi:{q:"शुद्ध लाल रंग के लिए सटीक HEX कलर कोड क्या है?",opts:["#FF0000","#00FF00","#0000FF","#FFFFFF"],ans:0,exp:"HEX रंग #RRGGBB प्रारूप का पालन करते हैं। शुद्ध लाल लाल चैनल (FF) को अधिकतम करता है और हरे और नीले (00) को बंद कर देता है, जिसके परिणामस्वरूप कोड #FF0000 बनता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which character entity must be used to display the 'greater than' sign (>) safely without confusing the browser?",opts:["&great;","&gt;","&#60;","&plus;"],ans:1,exp:"The 'greater than' sign (>) is a reserved character in HTML used to close tags. To display it safely as text, the character entity '&gt;' (or its numeric equivalent &#62;) must be used."},hi:{q:"ब्राउज़र को भ्रमित किए बिना सुरक्षित रूप से 'ग्रेटर देन' चिह्न (>) प्रदर्शित करने के लिए किस कैरेक्टर एंटिटी का उपयोग किया जाना चाहिए?",opts:["&great;","&gt;","&#60;","&plus;"],ans:1,exp:"'ग्रेटर देन' चिह्न (>) HTML में एक आरक्षित वर्ण है जिसका उपयोग टैग को बंद करने के लिए किया जाता है। इसे सुरक्षित रूप से टेक्स्ट के रूप में प्रदर्शित करने के लिए, कैरेक्टर एंटिटी '&gt;' (या इसके संख्यात्मक समकक्ष &#62;) का उपयोग किया जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"Which common URL scheme is specifically used for downloading or uploading files to a website?",opts:["http","https","file","ftp"],ans:3,exp:"The 'ftp' scheme stands for File Transfer Protocol. It is dedicated to the robust transferring, uploading, and downloading of files between a client and a server across a network."},hi:{q:"वेबसाइट पर फ़ाइलें डाउनलोड या अपलोड करने के लिए विशेष रूप से किस सामान्य URL स्कीम का उपयोग किया जाता है?",opts:["http","https","file","ftp"],ans:3,exp:"'ftp' स्कीम का अर्थ फाइल ट्रांसफर प्रोटोकॉल है। यह एक नेटवर्क में क्लाइंट और सर्वर के बीच फ़ाइलों को मज़बूती से स्थानांतरित करने, अपलोड करने और डाउनलोड करने के लिए समर्पित है।"}},
{type:"mcq",diff:"hard",en:{q:"According to XML structure, which of the following is a mandatory component of an XML document?",opts:["Document Type Definition (DTD)","Processing instructions","A single Document Element (root element)","An HTML <body> tag"],ans:2,exp:"A well-formed XML document must have exactly one root element (also called the Document Element) that completely encapsulates all other nested elements within the file."},hi:{q:"XML संरचना के अनुसार, निम्नलिखित में से कौन सा XML दस्तावेज़ का एक अनिवार्य घटक है?",opts:["डॉक्यूमेंट टाइप डेफिनिशन (DTD)","प्रोसेसिंग निर्देश","एक एकल डॉक्यूमेंट एलिमेंट (मूल तत्व/root element)","एक HTML <body> टैग"],ans:2,exp:"एक अच्छी तरह से बनाए गए (well-formed) XML दस्तावेज़ में ठीक एक मूल तत्व (root element) (जिसे दस्तावेज़ तत्व भी कहा जाता है) होना चाहिए जो फ़ाइल के भीतर अन्य सभी नेस्टेड तत्वों को पूरी तरह से घेरता हो।"}},
{type:"mcq",diff:"hard",en:{q:"In a Content Management System (CMS), what does the acronym CMA refer to?",opts:["Content Modification Access","Content Management Application","Central Media Administration","Content Management Algorithm"],ans:1,exp:"In a CMS, the CMA (Content Management Application) is the frontend editing component that provides an intuitive interface, allowing users to create, design, and modify website content seamlessly."},hi:{q:"कंटेंट मैनेजमेंट सिस्टम (CMS) में, CMA संक्षिप्त नाम का क्या अर्थ है?",opts:["कंटेंट मॉडिफिकेशन एक्सेस","कंटेंट मैनेजमेंट एप्लीकेशन","सेंट्रल मीडिया एडमिनिस्ट्रेशन","कंटेंट मैनेजमेंट एल्गोरिथम"],ans:1,exp:"CMS में, CMA (कंटेंट मैनेजमेंट एप्लीकेशन) फ्रंटएंड एडिटिंग घटक है जो एक सहज इंटरफ़ेस प्रदान करता है, जिससे उपयोगकर्ता मूल रूप से वेबसाइट सामग्री बना, डिज़ाइन और संशोधित कर सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following is an open-source CMS platform explicitly described as Google's blogging tool?",opts:["Joomla","Drupal","Blogger","Wix"],ans:2,exp:"Blogger is Google's dedicated web-based tool designed specifically to facilitate the easy creation, maintenance, and publishing of personal and professional blogs."},hi:{q:"निम्नलिखित में से कौन सा एक ओपन-सोर्स CMS प्लेटफ़ॉर्म है जिसे स्पष्ट रूप से Google के ब्लॉगिंग टूल के रूप में वर्णित किया गया है?",opts:["जुमला (Joomla)","ड्रुपल (Drupal)","ब्लॉगर (Blogger)","विक्स (Wix)"],ans:2,exp:"ब्लॉगर Google का समर्पित वेब-आधारित टूल है जिसे विशेष रूप से व्यक्तिगत और व्यावसायिक ब्लॉगों के आसान निर्माण, रखरखाव और प्रकाशन को सुविधाजनक बनाने के लिए डिज़ाइन किया गया है।"}},
{type:"mcq",diff:"hard",en:{q:"In the KompoZer interface, what does a 'red floppy icon' visually indicate on a document tab?",opts:["The document contains errors","The page has been edited but not saved yet","The file is currently being uploaded via FTP","The HTML source code is invalid"],ans:1,exp:"KompoZer allows tabbed editing. A red floppy disk icon on a specific tab serves as a visual warning that the corresponding web page contains unsaved changes and needs to be saved."},hi:{q:"कोम्पोजर (KompoZer) इंटरफ़ेस में, दस्तावेज़ टैब पर 'लाल फ़्लॉपी आइकन' दृश्य रूप से क्या दर्शाता है?",opts:["दस्तावेज़ में त्रुटियाँ हैं","पृष्ठ को संपादित किया गया है लेकिन अभी तक सहेजा नहीं गया है","फ़ाइल वर्तमान में FTP के माध्यम से अपलोड की जा रही है","HTML स्रोत कोड अमान्य है"],ans:1,exp:"कोम्पोजर टैब्ड एडिटिंग की अनुमति देता है। एक विशिष्ट टैब पर एक लाल फ्लॉपी डिस्क आइकन एक दृश्य चेतावनी के रूप में कार्य करता है कि संबंधित वेब पेज में बिना सहेजे गए परिवर्तन हैं और उन्हें सहेजा जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"Which KompoZer toolbar displays the hierarchical position of the cursor relative to HTML tags?",opts:["Format Toolbar","Tab Browser Toolbar","Edit Mode Toolbar","Status Toolbar"],ans:3,exp:"The Status Toolbar, located at the bottom of the KompoZer window, dynamically shows the HTML tag hierarchy relative to the current cursor position, allowing quick tag selection and property editing."},hi:{q:"कौन सा कोम्पोजर टूलबार HTML टैग के सापेक्ष कर्सर की पदानुक्रमित (hierarchical) स्थिति प्रदर्शित करता है?",opts:["फॉर्मेट टूलबार","टैब ब्राउज़र टूलबार","एडिट मोड टूलबार","स्टेटस टूलबार"],ans:3,exp:"स्टेटस टूलबार, कोम्पोजर विंडो के नीचे स्थित है, गतिशील रूप से वर्तमान कर्सर स्थिति के सापेक्ष HTML टैग पदानुक्रम (hierarchy) दिखाता है, जो त्वरित टैग चयन और प्रॉपर्टी संपादन की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the default port number assigned to the 'http' scheme in a URL?",opts:["21","80","443","8080"],ans:1,exp:"The default port for HTTP (HyperText Transfer Protocol) communication is 80. Unless another port is explicitly specified in the URL, web browsers default to port 80 when accessing standard web servers."},hi:{q:"URL में 'http' स्कीम को कौन सा डिफ़ॉल्ट पोर्ट नंबर असाइन किया गया है?",opts:["21","80","443","8080"],ans:1,exp:"HTTP (हाइपरटेक्स्ट ट्रांसफर प्रोटोकॉल) संचार के लिए डिफ़ॉल्ट पोर्ट 80 है। जब तक कि URL में स्पष्ट रूप से किसी अन्य पोर्ट को निर्दिष्ट नहीं किया जाता है, वेब ब्राउज़र मानक वेब सर्वर तक पहुँचते समय पोर्ट 80 पर डिफ़ॉल्ट होते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which attribute in an <iframe> tag is targeted by the 'target' attribute of a hyperlink to load the linked document inside the iframe?",opts:["id","class","name","src"],ans:2,exp:"To use an iframe as a target for a link, the <iframe> must have a 'name' attribute. The <a> tag's 'target' attribute must then match this exact name value."},hi:{q:"लिंक किए गए दस्तावेज़ को आईफ्रेम के अंदर लोड करने के लिए हाइपरलिंक के 'target' एट्रिब्यूट द्वारा <iframe> टैग में किस एट्रिब्यूट को लक्षित किया जाता है?",opts:["id","class","name","src"],ans:2,exp:"लिंक के लक्ष्य के रूप में आईफ्रेम का उपयोग करने के लिए, <iframe> में 'name' एट्रिब्यूट होना चाहिए। फिर <a> टैग के 'target' एट्रिब्यूट को इस सटीक नाम मान (name value) से मेल खाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"During URL Encoding, non-ASCII characters are converted into a valid format. Which symbol precedes the resulting two hexadecimal digits?",opts:["#","@","&","%"],ans:3,exp:"URL encoding converts problematic or non-ASCII characters into a universally accepted ASCII format. It does this by replacing the character with a percent sign (%) followed by two hexadecimal digits."},hi:{q:"URL एन्कोडिंग के दौरान, गैर-ASCII वर्णों को एक वैध प्रारूप में परिवर्तित किया जाता है। परिणामी दो हेक्साडेसिमल अंकों से पहले कौन सा प्रतीक आता है?",opts:["#","@","&","%"],ans:3,exp:"URL एन्कोडिंग समस्याग्रस्त या गैर-ASCII वर्णों को सार्वभौमिक रूप से स्वीकृत ASCII प्रारूप में परिवर्तित करता है। यह वर्ण को प्रतिशत चिह्न (%) के साथ बदलकर और उसके बाद दो हेक्साडेसिमल अंकों का उपयोग करके ऐसा करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which markup language represents arbitrary data structures, uses a Prologue, and focuses heavily on machine-readable data transfer?",opts:["DHTML","XHTML","XML","BML"],ans:2,exp:"Extensible Markup Language (XML) is highly versatile, focusing on describing arbitrary data structures rather than formatting. An XML document often starts with a Prologue (e.g., <?xml version=\"1.0\"?>)."},hi:{q:"कौन सी मार्कअप भाषा मनमाने डेटा संरचनाओं का प्रतिनिधित्व करती है, प्रोलॉग (Prologue) का उपयोग करती है, और मशीन-पठनीय डेटा ट्रांसफर पर भारी ध्यान केंद्रित करती है?",opts:["DHTML","XHTML","XML","BML"],ans:2,exp:"एक्सटेंसिबल मार्कअप लैंग्वेज (XML) अत्यधिक बहुमुखी है, जो स्वरूपण के बजाय मनमाने डेटा संरचनाओं का वर्णन करने पर ध्यान केंद्रित करती है। एक XML दस्तावेज़ अक्सर प्रोलॉग (Prologue) से शुरू होता है (उदा., <?xml version=\"1.0\"?>)।"}},
{type:"mcq",diff:"hard",en:{q:"In an HTML <form> element, which attribute strictly defines the server-side file or script that will process the submitted data?",opts:["method","action","enctype","target"],ans:1,exp:"The 'action' attribute is vital in a <form> tag. It contains the URL or file path of the server-side script (like PHP or ASP) that receives and processes the user's submitted input data."},hi:{q:"HTML <form> तत्व में, कौन सा एट्रिब्यूट कड़ाई से सर्वर-साइड फ़ाइल या स्क्रिप्ट को परिभाषित करता है जो सबमिट किए गए डेटा को संसाधित करेगा?",opts:["method","action","enctype","target"],ans:1,exp:"<form> टैग में 'action' एट्रिब्यूट महत्वपूर्ण है। इसमें सर्वर-साइड स्क्रिप्ट (जैसे PHP या ASP) का URL या फ़ाइल पथ होता है जो उपयोगकर्ता के सबमिट किए गए इनपुट डेटा को प्राप्त करता है और संसाधित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which block-level HTML element, when used correctly with CSS, entirely replaces the 'old way' of using tables for document layout?",opts:["<p>","<span>","<div>","<section>"],ans:2,exp:"The <div> tag is an arbitrary block-level container. With the advent of CSS, it has become the standard mechanism for structuring page layouts, overriding the outdated and incorrect practice of using <table> for layouts."},hi:{q:"कौन सा ब्लॉक-लेवल HTML तत्व, जब CSS के साथ सही ढंग से उपयोग किया जाता है, तो दस्तावेज़ लेआउट के लिए तालिकाओं (tables) का उपयोग करने के 'पुराने तरीके' को पूरी तरह से बदल देता है?",opts:["<p>","<span>","<div>","<section>"],ans:2,exp:"<div> टैग एक मनमाना ब्लॉक-लेवल कंटेनर है। CSS के आगमन के साथ, यह पेज लेआउट को संरचित करने के लिए मानक तंत्र बन गया है, जो लेआउट के लिए <table> का उपयोग करने की पुरानी और गलत प्रथा को खत्म करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which tag holds the specific description or definition associated with an item inside a <dl> list?",opts:["<dt>","<li>","<dd>","<desc>"],ans:2,exp:"In a definition list (<dl>), the <dt> tag contains the term, while the <dd> (definition description) tag provides the corresponding explanation or meaning of that term."},hi:{q:"कौन सा टैग <dl> सूची के अंदर किसी आइटम से जुड़े विशिष्ट विवरण या परिभाषा को रखता है?",opts:["<dt>","<li>","<dd>","<desc>"],ans:2,exp:"एक परिभाषा सूची (<dl>) में, <dt> टैग में शब्द (term) होता है, जबकि <dd> (परिभाषा विवरण) टैग उस शब्द का संबंधित स्पष्टीकरण या अर्थ प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"By default, how are the <li> elements visually marked inside an Unordered List (<ul>)?",opts:["With sequential numbers","With Roman numerals","With small black circles (bullets)","With letters (A, B, C)"],ans:2,exp:"An unordered list (<ul>) implies that the sequence of items does not matter. Browsers render these list items with bullets, typically appearing as small black circles by default."},hi:{q:"डिफ़ॉल्ट रूप से, <li> तत्वों को अनऑर्डर्ड सूची (<ul>) के अंदर दृश्य रूप से कैसे चिह्नित किया जाता है?",opts:["क्रमिक संख्याओं के साथ","रोमन अंकों के साथ","छोटे काले घेरे (बुलेट) के साथ","अक्षरों के साथ (A, B, C)"],ans:2,exp:"एक अनऑर्डर्ड सूची (<ul>) का अर्थ है कि आइटम के अनुक्रम से कोई फर्क नहीं पड़ता। ब्राउज़र इन सूची आइटमों को बुलेट के साथ प्रस्तुत करते हैं, जो आमतौर पर डिफ़ॉल्ट रूप से छोटे काले घेरे के रूप में दिखाई देते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In strict XHTML coding, what happens if the forward slash is omitted from the <hr /> empty element (i.e., using <hr>)?",opts:["The browser crashes","It becomes invalid XHTML","It creates a double line","It functions normally and is valid XHTML"],ans:1,exp:"In XHTML, strict structural rules mandate that all empty elements must be properly closed with a trailing slash. Using just <hr> instead of <hr /> breaks validation and results in invalid XHTML."},hi:{q:"सख्त XHTML कोडिंग में, यदि <hr /> खाली तत्व से फ़ॉरवर्ड स्लैश हटा दिया जाता है (अर्थात <hr> का उपयोग करके) तो क्या होता है?",opts:["ब्राउज़र क्रैश हो जाता है","यह अमान्य XHTML बन जाता है","यह एक दोहरी रेखा बनाता है","यह सामान्य रूप से कार्य करता है और मान्य XHTML है"],ans:1,exp:"XHTML में, सख्त संरचनात्मक नियम अनिवार्य करते हैं कि सभी खाली तत्वों को एक ट्रेलिंग स्लैश के साथ ठीक से बंद किया जाना चाहिए। <hr /> के बजाय सिर्फ <hr> का उपयोग करने से सत्यापन (validation) टूट जाता है और अमान्य XHTML बनता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which tag physically produces a strikethrough line across the text and is specifically named for that exact graphical effect?",opts:["<del>","<u>","<strike>","<s>"],ans:2,exp:"The <strike> element is historically used for its literal graphical effect of striking a line horizontally through the enclosed text. While deprecated in HTML5 in favor of <del> or CSS, it was specifically created for this presentation."},hi:{q:"कौन सा टैग भौतिक रूप से टेक्स्ट के पार एक स्ट्राइकथ्रू रेखा बनाता है और विशेष रूप से उसी ग्राफिकल प्रभाव के लिए नामित है?",opts:["<del>","<u>","<strike>","<s>"],ans:2,exp:"<strike> तत्व का ऐतिहासिक रूप से उपयोग संलग्न टेक्स्ट के माध्यम से क्षैतिज रूप से एक रेखा खींचने के शाब्दिक ग्राफिकल प्रभाव के लिए किया जाता है। जबकि HTML5 में <del> या CSS के पक्ष में इसे हटा (deprecated) दिया गया है, इसे विशेष रूप से इसी प्रस्तुति के लिए बनाया गया था।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following demonstrates the correct syntax for adding a CSS processing instruction in an XML Prologue?",opts:["<link rel='stylesheet' href='style.css'>","<?xml-stylesheet type=\"text/css\" href=\"style.css\"?>","<style src='style.css'/>","<?xml style=\"css\" file=\"style.css\"?>"],ans:1,exp:"In XML, a processing instruction allows passing information to applications. To link a CSS stylesheet in the XML Prologue, the strict format is: <?xml-stylesheet type=\"text/css\" href=\"style.css\"?>."},hi:{q:"निम्नलिखित में से कौन XML प्रोलॉग में CSS प्रोसेसिंग निर्देश जोड़ने के लिए सही सिंटैक्स प्रदर्शित करता है?",opts:["<link rel='stylesheet' href='style.css'>","<?xml-stylesheet type=\"text/css\" href=\"style.css\"?>","<style src='style.css'/>","<?xml style=\"css\" file=\"style.css\"?>"],ans:1,exp:"XML में, एक प्रोसेसिंग निर्देश अनुप्रयोगों को जानकारी पारित करने की अनुमति देता है। XML प्रोलॉग में CSS स्टाइलशीट को लिंक करने के लिए, सख्त प्रारूप है: <?xml-stylesheet type=\"text/css\" href=\"style.css\"?>।"}},
{type:"mcq",diff:"hard",en:{q:"Which Edit Mode in KompoZer explicitly allows users to view and manually edit the raw, pure HTML source code?",opts:["Normal view","HTML Tags view","HTML source view","Preview mode"],ans:2,exp:"KompoZer features multiple edit modes. The 'HTML source view' bypasses the WYSIWYG graphical interface, providing direct access to the raw, underlying HTML code for manual coding adjustments."},hi:{q:"कोम्पोजर में कौन सा एडिट मोड (Edit Mode) स्पष्ट रूप से उपयोगकर्ताओं को कच्चे, शुद्ध HTML स्रोत कोड को देखने और मैन्युअल रूप से संपादित करने की अनुमति देता है?",opts:["नॉर्मल व्यू (Normal view)","HTML टैग्स व्यू (HTML Tags view)","HTML सोर्स व्यू (HTML source view)","प्रिव्यू मोड (Preview mode)"],ans:2,exp:"कोम्पोजर में कई एडिट मोड होते हैं। 'HTML सोर्स व्यू' WYSIWYG ग्राफिकल इंटरफ़ेस को दरकिनार करता है, मैन्युअल कोडिंग समायोजन के लिए कच्चे, अंतर्निहित HTML कोड तक सीधी पहुँच प्रदान करता है।"}},
{type:"tf",diff:"hard",en:{q:"The fundamental design goals of XML place a heavy emphasis on simplicity, generality, and usability over the Internet.",opts:["True","False"],ans:0,exp:"True. Extensible Markup Language (XML) was meticulously designed to prioritize simplicity, extreme generality in arbitrary data definition, and broad usability for data exchange over internet networks."},hi:{q:"XML के मूलभूत डिज़ाइन लक्ष्य इंटरनेट पर सरलता, व्यापकता और उपयोगिता पर भारी जोर देते हैं।",opts:["सही","गलत"],ans:0,exp:"सही। एक्सटेंसिबल मार्कअप लैंग्वेज (XML) को सरलता, मनमाने डेटा परिभाषा में अत्यधिक व्यापकता और इंटरनेट नेटवर्क पर डेटा विनिमय के लिए व्यापक उपयोगिता को प्राथमिकता देने के लिए सावधानीपूर्वक डिज़ाइन किया गया था।"}},
{type:"tf",diff:"hard",en:{q:"In DHTML, the 'Dynamic Fonts' capability was originally developed and introduced by Microsoft exclusively for Internet Explorer.",opts:["True","False"],ans:1,exp:"False. The 'Dynamic Fonts' capability was a Netscape-only feature initially developed for Netscape Communicator to guarantee that pages rendered exactly as the designer intended regardless of local user fonts. Microsoft, on the other hand, developed 'Data binding'."},hi:{q:"DHTML में, 'डायनेमिक फ़ॉन्ट्स' क्षमता को मूल रूप से Microsoft द्वारा विशेष रूप से इंटरनेट एक्सप्लोरर के लिए विकसित और पेश किया गया था।",opts:["सही","गलत"],ans:1,exp:"गलत। 'डायनेमिक फ़ॉन्ट्स' क्षमता शुरुआत में नेटस्केप कम्युनिकेटर के लिए विकसित की गई एक नेटस्केप-ओनली विशेषता थी, ताकि यह गारंटी दी जा सके कि स्थानीय उपयोगकर्ता फ़ॉन्ट की परवाह किए बिना पृष्ठ बिल्कुल वैसे ही प्रस्तुत हों जैसा कि डिज़ाइनर चाहता था। दूसरी ओर, Microsoft ने 'डेटा बाइंडिंग' विकसित किया।"}}
];
